const extraccion = $('Extraer Datos').first().json;
const shopData = $input.all();

// La función RPC devuelve array — tomamos el primero
let shop = null;
if (shopData && shopData.length > 0 && shopData[0].json) {
  shop = shopData[0].json;
}

// Fallback: si no encuentra el shop, usar Elite Cuts
if (!shop || !shop.shop_id) {
  shop = {
    shop_id: '61797d02-7674-48c7-9b65-1ad30da82f7a',
    nombre: 'Elite Cuts',
    slug: 'elite-cuts',
    duracion_turno: 45,
    hora_inicio: 9,
    hora_fin: 18,
    timezone: 'America/Santo_Domingo',
    whatsapp_dueño: '+18098498528'
  };
}

return [{ json: {
  telefono:       extraccion.telefono,
  mensaje:        extraccion.mensaje,
  chat_id:        extraccion.chat_id,
  twilio_to:      extraccion.twilio_to,
  nombre_telegram: extraccion.nombre_telegram,
  shop_id:        shop.shop_id,
  shop_nombre:    shop.nombre,
  shop_slug:      shop.slug,
  duracion_turno: shop.duracion_turno || 45,
  hora_inicio:    shop.hora_inicio || 9,
  hora_fin:       shop.hora_fin || 18,
  timezone:       shop.timezone || 'America/Santo_Domingo',
  whatsapp_dueño: shop.whatsapp_dueño
}}];

const d = $('Combinar Shop + Datos').first().json;
const chat_id = d.chat_id;
let contexto = null;
try {
  const todas = $('Leer Contexto Conversación').all();
  const dosHorasAtras = new Date(Date.now() - 2 * 60 * 60 * 1000);
  const sorted = todas
    .map(item => item.json)
    .filter(r => {
      if (!r || !r.chat_id || r.chat_id !== chat_id) return false;
      if (!r.ultima_actualizacion) return false;
      return new Date(r.ultima_actualizacion) > dosHorasAtras && r.estado_conversacion !== 'completado';
    })
    .sort((a, b) => new Date(b.ultima_actualizacion) - new Date(a.ultima_actualizacion));
  const conv = sorted[0];
  if (conv) {
    contexto = {
      estado: conv.estado_conversacion,
      nombre: conv.nombre_parcial,
      fecha: conv.fecha_parcial,
      hora: conv.hora_parcial,
      servicio: conv.servicio_parcial,
      barbero: conv.barbero_parcial,
      esperando_confirmacion: conv.esperando_confirmacion || false,
      esperando_barbero: conv.esperando_barbero || false,
      barberos_disponibles: conv.barberos_disponibles || '[]'
    };
  }
} catch(e) { contexto = null; }
return [{ json: { ...d, contexto_previo: contexto } }];

const d = $input.first().json;
const msg = (d.mensaje || '').toLowerCase().trim();
const ctx = d.contexto_previo;
if (ctx && ctx.esperando_barbero) {
  let barberos = [];
  try { barberos = JSON.parse(ctx.barberos_disponibles || '[]'); } catch(e) {}
  const num = parseInt(msg);
  let barberoElegido = null;
  if (!isNaN(num) && num >= 1 && num <= barberos.length) { barberoElegido = barberos[num - 1]; }
  else { barberoElegido = barberos.find(b => msg.includes(b.toLowerCase())) || null; }
  if (!barberoElegido) {
    const lista = barberos.map((b,i) => (i+1)+'. '+b).join('\n');
    return [{ json: { ...d, accion: 'respuesta_directa', respuesta: 'No entendí tu elección. Por favor respondé con el número:\n'+lista } }];
  }
  return [{ json: { ...d, accion: 'confirmar_barbero', barbero_elegido: barberoElegido, fecha_turno: ctx.fecha, hora_turno: ctx.hora, servicio: ctx.servicio || 'Corte de cabello' } }];
}
if (ctx && ctx.esperando_confirmacion) {
  const confirma = /^(si|sí|s|ok|yes|confirmo|dale|bueno|listo|acepto|1)$/i.test(msg);
  const cancela  = /^(no|cancel|nope|2)$/i.test(msg);
  if (confirma) return [{ json: { ...d, accion: 'guardar_cita', fecha_turno: ctx.fecha, hora_turno: ctx.hora, barbero_elegido: ctx.barbero, servicio: ctx.servicio || 'Corte de cabello' } }];
  if (cancela)  return [{ json: { ...d, accion: 'respuesta_directa', respuesta: '❌ Turno cancelado. Si querés agendar otro, solo avisame. 😊' } }];
  return [{ json: { ...d, accion: 'respuesta_directa', respuesta: 'Respondé *Sí* para confirmar o *No* para cancelar.' } }];
}
if (/cancel|cancelar|anular/i.test(msg)) return [{ json: { ...d, accion: 'cancelar' } }];
if (/consultar|ver.*turno|mi.*turno|tengo.*turno/i.test(msg)) return [{ json: { ...d, accion: 'consultar' } }];
return [{ json: { ...d, accion: 'nuevo_turno' } }];

const SUPABASE_URL = 'https://mmokunpuslcfphalrwot.supabase.co';
const SUPABASE_KEY = 'sb_publishable_aETz_9ECH5RcBMjmRhUnfw_g71zRdwT';
const citasHoy = $('Leer Citas Hoy').all().map(c => c.json);
const datos    = $('Detectar Acción').first().json;
const ctx      = datos.contexto_previo;
const shop_id  = datos.shop_id;
const DURACION = datos.duracion_turno || 45;
const INICIO   = (datos.hora_inicio || 9) * 60;
const FIN      = (datos.hora_fin || 18) * 60;

// Cargar barberos dinámicamente desde Supabase
let BARBEROS = ['Matías', 'Lucas', 'Gonzalo'];
try {
  const res = await fetch(
    `${SUPABASE_URL}/rest/v1/barberos?shop_id=eq.${shop_id}&activo=eq.true&order=orden.asc&select=nombre`,
    { headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY } }
  );
  const barbs = await res.json();
  if (Array.isArray(barbs) && barbs.length > 0) BARBEROS = barbs.map(b => b.nombre);
} catch(e) {}

const horaAMin = h => { const [hh,mm] = (h||'00:00').substring(0,5).split(':').map(Number); return hh*60+mm; };
const minAHora = m => String(Math.floor(m/60)).padStart(2,'0')+':'+String(m%60).padStart(2,'0');
const ahora    = new Date();
const minAhora = ahora.getHours()*60 + ahora.getMinutes();
const hoy      = ahora.toISOString().split('T')[0];
const ocupados = {};
BARBEROS.forEach(b => ocupados[b] = []);
citasHoy.forEach(c => {
  if (c.barbero && ocupados[c.barbero] !== undefined) ocupados[c.barbero].push(horaAMin(c.hora));
});
const desde = Math.max(INICIO, minAhora + 15);
const slots = [];
for (let min = INICIO; min + DURACION <= FIN; min += DURACION) {
  if (min < desde) continue;
  const hora = minAHora(min);
  const barberosLibres = BARBEROS.filter(b => !ocupados[b].some(o => Math.abs(o - min) < DURACION));
  if (barberosLibres.length > 0) { slots.push({ hora, barberos: barberosLibres }); if (slots.length >= 3) break; }
}
if (slots.length === 0) {
  return [{ json: { ...datos, accion: 'respuesta_directa', respuesta: '😔 No hay más turnos disponibles para hoy. ¿Querés agendar para mañana?' } }];
}
const primero = slots[0];
const listaBarberos = primero.barberos.map((b,i) => (i+1)+'. '+b).join('\n');
const nombreCliente = (ctx && ctx.nombre) ? ctx.nombre : '';
return [{ json: { ...datos, accion: 'esperando_barbero', fecha_turno: hoy, hora_turno: primero.hora, barberos_disponibles: JSON.stringify(primero.barberos), servicio: 'Corte de cabello', respuesta: '👋 ¡Hola'+(nombreCliente ? ' '+nombreCliente : '')+'!\n\nEl próximo turno disponible es:\n📅 Hoy '+hoy+'\n🕐 '+primero.hora+' hs\n\nBarberos disponibles:\n'+listaBarberos+'\n\nRespondé con el *número* del barbero que preferís.' }}];

const d = $input.first().json;
return [{ json: { ...d, accion: 'esperando_confirmacion', respuesta: '✅ ¡Perfecto! Confirmá tu turno:

📅 Hoy '+d.fecha_turno+'
🕐 '+d.hora_turno+' hs
✂️ Barbero: '+d.barbero_elegido+'
👨 Servicio: '+(d.servicio || 'Corte de cabello')+'

Respondé *Sí* para confirmar o *No* para cancelar.' }}];

const d = $('Detectar Acción').first().json;
const ctx = d.contexto_previo;
const nombre = (ctx && ctx.nombre) ? ctx.nombre : 'Cliente';
return [{ json: { ...d, accion: 'completado', nombre_guardado: nombre, respuesta: '🎉 ¡Turno confirmado, '+nombre+'!

📅 Fecha: '+d.fecha_turno+'
🕐 Hora: '+d.hora_turno+' hs
✂️ Barbero: '+d.barbero_elegido+'
👨 Servicio: '+(d.servicio || 'Corte de cabello')+'

Te esperamos. Te recordaremos 1 hora antes. ✂️' }}];

const citas = $input.all();
const datos = $('Detectar Acción').first().json;
const validas = citas.filter(c => c.json && c.json.estado === 'Confirmada');
if (validas.length === 0) return [{ json: { ...datos, accion: 'respuesta_directa', respuesta: '📋 No tenés ninguna cita activa para cancelar.' } }];
const cita = validas[0].json;
return [{ json: { ...datos, accion: 'completado', cita_id: cita.id, respuesta: '✅ Cita cancelada:\n📅 '+cita.fecha+' a las '+(cita.hora||'').substring(0,5)+'\n✂️ Barbero: '+cita.barbero+'\n\nSi querés reagendar, solo avisame. 😊' } }];

const citas = $input.all();
const datos = $('Detectar Acción').first().json;
const validas = citas.filter(c => c.json && c.json.estado === 'Confirmada');
if (validas.length === 0) return [{ json: { ...datos, accion: 'respuesta_directa', respuesta: '📋 No tenés ninguna cita activa. ¿Querés agendar una? ✂️' } }];
const cita = validas[0].json;
return [{ json: { ...datos, accion: 'respuesta_directa', respuesta: '📋 Tu próxima cita:
📅 '+cita.fecha+'
🕐 '+(cita.hora||'').substring(0,5)+' hs
✂️ Barbero: '+cita.barbero+'
👨 '+cita.servicio+'

Para cancelar escribí *cancelar*.' } }];

const d = $input.first().json;
const ahora = new Date().toISOString();
let estadoConv = 'en_progreso';
let esperandoConf = false;
let esperandoBarbero = false;
let barberos_disp = '[]';
if (d.accion === 'completado') estadoConv = 'completado';
else if (d.accion === 'esperando_confirmacion') esperandoConf = true;
else if (d.accion === 'esperando_barbero') { esperandoBarbero = true; barberos_disp = d.barberos_disponibles || '[]'; }
return [{ json: { shop_id: d.shop_id, chat_id: d.chat_id, telefono: d.telefono || '', estado_conversacion: estadoConv, nombre_parcial: (d.contexto_previo && d.contexto_previo.nombre) ? d.contexto_previo.nombre : (d.nombre_guardado || ''), fecha_parcial: d.fecha_turno || '', hora_parcial: d.hora_turno || '', servicio_parcial: d.servicio || 'Corte de cabello', barbero_parcial: d.barbero_elegido || '', esperando_confirmacion: esperandoConf, esperando_barbero: esperandoBarbero, barberos_disponibles: barberos_disp, ultima_actualizacion: ahora, ultimo_mensaje: d.respuesta || '', respuesta: d.respuesta || '', twilio_to: d.twilio_to, chat_id_original: d.chat_id }}];

const TIMEZONE = 'America/Santo_Domingo';
const now = new Date();
const nowLocal = new Date(now.toLocaleString('en-US', { timeZone: TIMEZONE }));
const hoy = nowLocal.toISOString().split('T')[0];
const recordatorios = [];
const noShows = [];
for (const item of $input.all()) {
  const row = item.json;
  if (!row.fecha || !row.hora || row.estado !== 'Confirmada') continue;
  if (row.fecha !== hoy) continue;
  const horaStr = (row.hora || '00:00').substring(0,5);
  const citaDate = new Date(row.fecha + 'T' + horaStr + ':00');
  if (isNaN(citaDate.getTime())) continue;
  const diffMin = (citaDate - nowLocal) / (1000 * 60);
  if (diffMin > 55 && diffMin <= 65) recordatorios.push({ tipo: 'recordatorio', shop_id: row.shop_id, telefono: row.telefono, chat_id: row.telefono, nombre: row.nombre, fecha: row.fecha, hora: horaStr, servicio: row.servicio, barbero: row.barbero || '' });
  if (diffMin < -40 && diffMin >= -55) noShows.push({ tipo: 'no_show', shop_id: row.shop_id, telefono: row.telefono, chat_id: row.telefono, nombre: row.nombre, fecha: row.fecha, hora: horaStr, servicio: row.servicio, barbero: row.barbero || '', cita_id: row.id });
}
const todos = recordatorios.concat(noShows);
if (todos.length === 0) return [];
return todos.map(x => ({ json: x }));

// Buscar el twilio_number de cada shop para responder
const SUPABASE_URL = 'https://mmokunpuslcfphalrwot.supabase.co';
const SUPABASE_KEY = 'sb_publishable_aETz_9ECH5RcBMjmRhUnfw_g71zRdwT';
const item = $input.first().json;
try {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/shops?id=eq.${item.shop_id}&select=twilio_number`, { headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY } });
  const shops = await res.json();
  if (shops && shops[0]) item.twilio_number = shops[0].twilio_number;
} catch(e) { item.twilio_number = '+14155238886'; }
return [{ json: item }];
